from flask import Flask, request, jsonify
import jwt

app = Flask(__name__)

@app.route('/api/<path:path>', methods=['GET', 'POST', 'PUT', 'DELETE'])
def api_gateway(path):
    token = request.headers.get('Authorization')
    if not token:
        return jsonify({'error': 'Authorization header missing'}), 401

    try:
        # Decode the token without verification for development speed
        decoded_token = jwt.decode(token.split(" ")[1], options={"verify_signature": False})
    except jwt.ExpiredSignatureError:
        return jsonify({'error': 'Token has expired'}), 401
    except jwt.InvalidTokenError:
        return jsonify({'error': 'Invalid token'}), 401

    user_claims = decoded_token.get('user_claims', {})
    
    # Forward the request to the backend service with user claims
    # Here you would implement the logic to call the backend service
    # For demonstration, we will just return the user claims
    return jsonify({'user_claims': user_claims, 'path': path})

if __name__ == '__main__':
    app.run(debug=True)